import{_ as e,c as a,o as s,a4 as n}from"./chunks/framework.HaEZziQ1.js";const o="/FrontEndLearnNotes/assets/image-20240306182349834.BkXE2j8g.png",l="/FrontEndLearnNotes/assets/image-20240306182430920.ztRfvAcP.png",r="/FrontEndLearnNotes/assets/image-20240306182521323.mejUkHIF.png",B=JSON.parse('{"title":"CSS开发技巧","description":"","frontmatter":{},"headers":[],"relativePath":"Document/HTML和CSS/CSS/CSS开发技巧.md","filePath":"Document/HTML和CSS/CSS/CSS开发技巧.md","lastUpdated":1709727320000}'),t={name:"Document/HTML和CSS/CSS/CSS开发技巧.md"},p=n('<h1 id="css开发技巧" tabindex="-1">CSS开发技巧 <a class="header-anchor" href="#css开发技巧" aria-label="Permalink to &quot;CSS开发技巧&quot;">​</a></h1><p>灵活运用CSS开发技巧：<a href="https://juejin.cn/post/6844903926110617613" target="_blank" rel="noreferrer">https://juejin.cn/post/6844903926110617613</a></p><p>Css Sprite精灵图：<a href="https://www.jb51.cc/css-sprite-tutorial/1187472.html" target="_blank" rel="noreferrer">https://www.jb51.cc/css-sprite-tutorial/1187472.html</a></p><h2 id="_1-first-letter-drop-首字母丢失" tabindex="-1">1. First letter drop 首字母丢失 <a class="header-anchor" href="#_1-first-letter-drop-首字母丢失" aria-label="Permalink to &quot;1. First letter drop 首字母丢失&quot;">​</a></h2><p><img src="'+o+`" alt="image-20240306182349834"></p><p>我们可以使用 <code>:first-letter</code> 来删除文本的第一个字母：</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">p</span><span style="color:#56B6C2;">:first-letter</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;"> font-size: </span><span style="color:#D19A66;">200</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;"> color: </span><span style="color:#D19A66;">#8A2BE2</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>:first-letter</code> 选择器用于指定元素的首字母样式，它仅适用于块级元素。效果如下:</p><p><a href="https://codepen.io/OMGZui/pen/oNEMVvN" target="_blank" rel="noreferrer">first-letter (codepen.io)</a></p><h2 id="_2-图像文本环绕" tabindex="-1">2. 图像文本环绕 <a class="header-anchor" href="#_2-图像文本环绕" aria-label="Permalink to &quot;2. 图像文本环绕&quot;">​</a></h2><p><img src="`+l+`" alt="image-20240306182430920"></p><p>CSS 中的 <code>shape-outside</code> 属性是一个非常有用且强大的工具，它允许设计师和开发者控制内容如何围绕一个浮动元素（通常是图像或图形）进行排列。通过定义这个属性中的形状，您可以创建更复杂和吸引人的布局，使文本环绕复杂的形状，而不仅仅是通常的矩形。</p><p><code>shape-outside</code> 属性定义了内容将围绕其排列的形状。它通常与 float 属性一起使用，因为只有浮动的元素才会有内容围绕它。</p><p><strong>可用的值:</strong></p><ol><li>none: 默认值。不创建任何形状；内容围绕元素的盒子进行排列。</li><li><code>&lt;shape-box&gt;</code>: 使用元素的边距盒、边框盒、填充盒或内容盒作为参考盒。</li></ol><ul><li>margin-box</li><li>border-box</li><li>padding-box</li><li>content-box</li></ul><ol><li><code>&lt;basic-shape&gt;</code>: 可以定义一个基本的形状，例如：</li></ol><ul><li>circle()</li><li>ellipse()</li><li>inset()</li><li>polygon()</li></ul><ol><li><code>&lt;image&gt;</code>: 一个图像可以用作形状的参考。图像的 alpha 通道决定了形状的尺寸。</li></ol><h4 id="举例" tabindex="-1">举例 <a class="header-anchor" href="#举例" aria-label="Permalink to &quot;举例&quot;">​</a></h4><p>使用椭圆:</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.element</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">    float: </span><span style="color:#D19A66;">left</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">    shape-outside: </span><span style="color:#56B6C2;">ellipse</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">50</span><span style="color:#E06C75;">%</span><span style="color:#D19A66;"> 50</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;"> at </span><span style="color:#D19A66;">50</span><span style="color:#E06C75;">%</span><span style="color:#D19A66;"> 50</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>使用多边形:</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.element</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">    float: </span><span style="color:#D19A66;">left</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">    shape-outside: </span><span style="color:#56B6C2;">polygon</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">0</span><span style="color:#E06C75;">%</span><span style="color:#D19A66;"> 0</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">100</span><span style="color:#E06C75;">%</span><span style="color:#D19A66;"> 0</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">50</span><span style="color:#E06C75;">%</span><span style="color:#D19A66;"> 100</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>使用图像:</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.element</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">    float: </span><span style="color:#D19A66;">left</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">    shape-outside: </span><span style="color:#56B6C2;">url</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;path-to-image.png&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h4 id="实际应用" tabindex="-1">实际应用 <a class="header-anchor" href="#实际应用" aria-label="Permalink to &quot;实际应用&quot;">​</a></h4><p>假设你有一个圆形图像，您希望文本围绕它排列，同时尊重圆的边界。没有 shape-outside，文本只会围绕图像的矩形边界盒子进行排列。但使用 <code>shape-outside</code>，可以使文本平滑地围绕圆形图像进行排列，从而得到更加视觉上吸引人的布局。</p><p>整合地址：<a href="https://codepen.io/OMGZui/pen/JjpBzGP" target="_blank" rel="noreferrer">shape-outside (codepen.io)</a></p><h2 id="_3-使用-where-简化代码" tabindex="-1">3. 使用 <code>:where()</code> 简化代码 <a class="header-anchor" href="#_3-使用-where-简化代码" aria-label="Permalink to &quot;3. 使用 \`:where()\` 简化代码&quot;">​</a></h2><p>当将同一样式应用于多个元素时，CSS可能会像这样：</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.page</span><span style="color:#E06C75;"> div</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#D19A66;">.paget</span><span style="color:#D19A66;"> .title</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#D19A66;">.page</span><span style="color:#61AFEF;"> #article</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">   color: </span><span style="color:#D19A66;">red</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这段代码看起来并不是很易读，而 <code>:where()</code> 伪类就派上了用场。 <code>:where()</code> 伪类函数接受一个选择器列表作为其参数，并将选择所有可以由选择器列表中的任何规则选择的元素。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.page</span><span style="color:#56B6C2;"> :where</span><span style="color:#C678DD;">(</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">,</span><span style="color:#D19A66;"> .title</span><span style="color:#ABB2BF;">,</span><span style="color:#61AFEF;"> #article</span><span style="color:#C678DD;">)</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;"> color: </span><span style="color:#D19A66;">red</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="_4-透明图像的阴影" tabindex="-1">4. 透明图像的阴影 <a class="header-anchor" href="#_4-透明图像的阴影" aria-label="Permalink to &quot;4. 透明图像的阴影&quot;">​</a></h2><p><img src="`+r+`" alt="image-20240306182521323"></p><p>你是否曾尝试在透明图像上添加 box-shadow ，结果却看起来像是你添加了边框？我想我们都有过这样的经历。为透明图像添加阴影效果的解决方案是使用 <code>drop-shadow</code> 。</p><p>它的工作方式是， <code>drop-shadow</code> 属性遵循给定图像的<code>alpha</code>通道。因此，阴影是基于图像内部的形状，而不是显示在其外部。</p><p>事例地址：<a href="https://codepen.io/OMGZui/pen/bGLjJNO" target="_blank" rel="noreferrer">shadow (codepen.io)</a></p><h2 id="_5-文字的打字效果" tabindex="-1">5. 文字的打字效果 <a class="header-anchor" href="#_5-文字的打字效果" aria-label="Permalink to &quot;5. 文字的打字效果&quot;">​</a></h2><p>网页设计正在以每分钟的速度变得更富创意。借助CSS动画功能，您可以让您的网页充满生机。在这个例子中，我们使用动画和<code>@keyframes</code>属性来实现打字机效果。</p><p>具体来说，对于这个演示，我们实现了 <code>steps()</code> 属性来分割我们的文本动画。首先，你需要指定 <code>steps()</code> 的数量，就我们的情况来说，这是我们希望进行动画处理的文本的字符长度。</p><p>其次，我们使用 <code>@keyframes</code> 来声明动画何时开始。例如，如果你在“文字打字效果”后面写了另一个词，除非你改变CSS片段中的 steps() 数量，否则动画将无法工作。</p><p>也就是说，这种效果并不是特别新颖。然而，尽管可以通过使用CSS达到同样的效果，但大多数开发者仍然会选择使用JavaScript库。</p><p>事例地址：<a href="https://codepen.io/OMGZui/pen/MWQBxqd" target="_blank" rel="noreferrer">Typing Effect (codepen.io)</a></p><h2 id="_6-设置自定义光标" tabindex="-1">6. 设置自定义光标 <a class="header-anchor" href="#_6-设置自定义光标" aria-label="Permalink to &quot;6. 设置自定义光标&quot;">​</a></h2><p>你可能永远不需要强制让你的访客使用独特的光标。至少，对于一般的用户体验目的来说是这样。然而，关于 <code>cursor</code> 属性的一点值得注意的是，它允许你展示图片。这相当于以照片格式展示工具提示。</p><p>一些使用场景包括能够比较两张不同的照片，而无需在视口中渲染这些照片。例如，可以使用光标属性来节省设计中的空间。由于你可以将自定义光标锁定到特定的 <code>div</code>元素上，所以它不会干扰到元素之外的其他元素。</p><p>事例地址：<a href="https://codepen.io/OMGZui/pen/abqjMXd" target="_blank" rel="noreferrer">cursor (codepen.io)</a></p><h2 id="_7-纯css的清单" tabindex="-1">7. 纯CSS的清单 <a class="header-anchor" href="#_7-纯css的清单" aria-label="Permalink to &quot;7. 纯CSS的清单&quot;">​</a></h2><p>正如我在文章开头提到的，CSS正在稳步发展。而这个动态清单的演示就是一个很好的例证。</p><p>它的工作方式是我们将复选框输入类型与 <code>:checked</code> 伪类一起使用。并使用 transform 属性在 <code>:checked</code> 规范返回真值时更改状态。</p><p>使用这种方法可以实现各种各样的目标。例如，当用户点击特定的复选框时，切换隐藏的内容。它适用于单选和复选框等输入类型，但也可以应用于<code>&lt;option&gt;</code>和<code>&lt;select&gt;</code>元素。</p><p>事例地址：<a href="https://codepen.io/OMGZui/pen/yLvqwZW" target="_blank" rel="noreferrer">checklist (codepen.io)</a></p><h3 id="_1-自定义光标-cursor" tabindex="-1">1. 自定义光标（cursor） <a class="header-anchor" href="#_1-自定义光标-cursor" aria-label="Permalink to &quot;1. 自定义光标（cursor）&quot;">​</a></h3><p>首先来看一下<code>CSS</code>的内置光标样式。平时开发中用到的基本上就是<code>default</code>、<code>pointer</code>、<code>not-allowed</code>、<code>move</code>这几个。其实内置的光标样式还有很多，大家可以把鼠标放到下面的颜色块上体验一下。</p><p>自定义光标也很简单，只需要通过<code>cursor: url(xxx)</code>引入一张图片即可。有时候我们下载的<code>chrome</code>主题会改变光标的样式，用的就是这个方法。</p><p><a href="https://code.juejin.cn/pen/7187210955057528888" target="_blank" rel="noreferrer">鼠标光标样式 - 码上掘金 (juejin.cn)</a></p><h3 id="_2-自定义placeholder样式-placeholder" tabindex="-1">2. 自定义placeholder样式（::placeholder） <a class="header-anchor" href="#_2-自定义placeholder样式-placeholder" aria-label="Permalink to &quot;2. 自定义placeholder样式（::placeholder）&quot;">​</a></h3><p>如果一个输入框是必填的，如果没有输入具体值，在失焦的情况下一般都会标红提示。这时候也可以把<code>placeholder</code>变成红色的达到更加醒目的效果。</p><p><a href="https://code.juejin.cn/pen/7187211344746119200" target="_blank" rel="noreferrer">自定义placeholder字体颜色 - 码上掘金 (juejin.cn)</a></p><h3 id="_3-自定义选中样式-selection" tabindex="-1">3. 自定义选中样式（::selection） <a class="header-anchor" href="#_3-自定义选中样式-selection" aria-label="Permalink to &quot;3. 自定义选中样式（::selection）&quot;">​</a></h3><p>有时候我们看到网页的文字选中会有特殊的样式，就是通过<code>::selection</code>这个伪元素来实现的。</p><p><code>::selection</code>伪元素用来应用于文档中被用户高亮的部分。在使用这个伪元素时，有一点需要注意，只有以下这些<code>CSS</code>属性可以用于<code>::selection</code> 选择器：</p><ul><li><a href="https://link.juejin.cn/?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fzh-CN%2Fdocs%2FWeb%2FCSS%2Fcolor" target="_blank" rel="noreferrer"><code>color</code></a></li><li><a href="https://link.juejin.cn/?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fzh-CN%2Fdocs%2FWeb%2FCSS%2Fbackground-color" target="_blank" rel="noreferrer"><code>background-color</code></a></li><li><a href="https://link.juejin.cn/?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fzh-CN%2Fdocs%2FWeb%2FCSS%2Fcursor" target="_blank" rel="noreferrer"><code>cursor</code></a></li><li><a href="https://link.juejin.cn/?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fzh-CN%2Fdocs%2FWeb%2FCSS%2Fcaret-color" target="_blank" rel="noreferrer"><code>caret-color</code></a></li><li><a href="https://link.juejin.cn/?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fzh-CN%2Fdocs%2FWeb%2FCSS%2Foutline" target="_blank" rel="noreferrer"><code>outline</code></a></li><li><a href="https://link.juejin.cn/?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fzh-CN%2Fdocs%2FWeb%2FCSS%2Ftext-decoration" target="_blank" rel="noreferrer"><code>text-decoration</code></a></li><li><a href="https://link.juejin.cn/?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ftext-emphasis-color" target="_blank" rel="noreferrer"><code>text-emphasis-color</code> (en-US)</a></li><li><a href="https://link.juejin.cn/?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fzh-CN%2Fdocs%2FWeb%2FCSS%2Ftext-shadow" target="_blank" rel="noreferrer"><code>text-shadow</code></a></li></ul><p><a href="https://code.juejin.cn/pen/7187212680875704377" target="_blank" rel="noreferrer">选中文字背景变色 - 码上掘金 (juejin.cn)</a></p><h3 id="_4-禁止用户选择-可以整段选择-user-select" tabindex="-1">4. 禁止用户选择 &amp; 可以整段选择（user-select） <a class="header-anchor" href="#_4-禁止用户选择-可以整段选择-user-select" aria-label="Permalink to &quot;4. 禁止用户选择 &amp; 可以整段选择（user-select）&quot;">​</a></h3><p>有些网站会禁止用户选中内容进行复制，在CSS层面可以通过<code>user-select: none</code>来实现。</p><p><code>user-select</code>属性用来控制用户能否选中文本。它可以接收的参数还有<code>auto</code>、<code>text</code>、<code>contain</code>、<code>all</code>等。</p><p>当为<code>all</code>时，当点击子元素或者上下文时，包含该子元素的最顶层元素也会被选中。有了这个属性，我们在复制整篇内容时，不用先选中然后通过拖动滚动条来实现复制大段的内容了，可以通过先找到想要复制的元素的根元素，然后给它加上<code>user-select: all</code>的属性，就可以轻松的点击一下就全部选中了。</p><p><a href="https://code.juejin.cn/pen/7187213869830373388" target="_blank" rel="noreferrer">选择整段文字的方式 - 码上掘金 (juejin.cn)</a></p><h3 id="_5-禁止鼠标事件-pointer-events" tabindex="-1">5. 禁止鼠标事件（pointer-events） <a class="header-anchor" href="#_5-禁止鼠标事件-pointer-events" aria-label="Permalink to &quot;5. 禁止鼠标事件（pointer-events）&quot;">​</a></h3><p>在有些需求中，需要禁止用户点击某个区域，看起来鼠标在这个区域完全不起作用，不会响应相应的事件。这时候可以通过<code>pointer-events</code>属性来限制。</p><p><code>pointer-events</code>属性用来指定在什么情况下某个特定的图形元素可以成为鼠标事件的<code>target</code>。把它设置成<code>none</code>即可到达效果。</p><p><a href="https://code.juejin.cn/pen/7187214405023563831" target="_blank" rel="noreferrer">禁止鼠标点击事件 - 码上掘金 (juejin.cn)</a></p><h3 id="_6-让网站变灰-filter-grayscale" tabindex="-1">6. 让网站变灰（filter:grayscale） <a class="header-anchor" href="#_6-让网站变灰-filter-grayscale" aria-label="Permalink to &quot;6. 让网站变灰（filter:grayscale）&quot;">​</a></h3><p>在一些公祭日的时候，我们浏览网站通常都会发现网站整体风格都会变成灰色的。这种效果就是用<code>filter</code>这个属性实现的。</p><p><code>filter</code>属性可以将模糊或颜色偏移等图形效果应用于元素，可以接收的函数包括：</p><ul><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fblur" target="_blank" rel="noreferrer"><code>blur()</code></a>、</li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fbrightness" target="_blank" rel="noreferrer"><code>brightness()</code></a></li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fcontrast" target="_blank" rel="noreferrer"><code>contrast()</code></a></li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fgrayscale" target="_blank" rel="noreferrer"><code>grayscale()</code></a></li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fhue-rotate" target="_blank" rel="noreferrer"><code>hue-rotate()</code></a></li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Finvert" target="_blank" rel="noreferrer"><code>invert()</code></a></li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fopacity" target="_blank" rel="noreferrer"><code>opacity()</code></a></li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fsaturate" target="_blank" rel="noreferrer"><code>saturate()</code></a></li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fsepia" target="_blank" rel="noreferrer"><code>sepia()</code></a></li><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FWeb%2FCSS%2Ffilter-function%2Fdrop-shadow" target="_blank" rel="noreferrer"><code>drop-shadow()</code></a></li></ul><p>其中<code>grayscale(）</code>函数的作用就是将图片转换成灰度，可以接收数字或者百分比参数。0代表不做处理，1代表完全变成灰度。两者之间的数值通过线性插值来生成具体的灰度值。不传参默认为1。所以我们用<code>filter:grayscale()</code>一行代码就可以实现让网站变灰的效果。</p><p><a href="https://code.juejin.cn/pen/7187214942305517600" target="_blank" rel="noreferrer">前端页面一键置黑 - 码上掘金 (juejin.cn)</a></p><h3 id="_7-多行文本截断展示省略号-webkit-line-clamp" tabindex="-1">7. 多行文本截断展示省略号(-webkit-line-clamp) <a class="header-anchor" href="#_7-多行文本截断展示省略号-webkit-line-clamp" aria-label="Permalink to &quot;7. 多行文本截断展示省略号(-webkit-line-clamp)&quot;">​</a></h3><p>单行文本截断展示省略号的方法估计大家已经应用的很是得心应手了。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">white-space</span><span style="color:#C678DD;">: nowrap; </span></span>
<span class="line"><span style="color:#C678DD;">overflow: hidden; </span></span>
<span class="line"><span style="color:#E06C75;">text-overflow</span><span style="color:#C678DD;">: ellipsis;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>多行文本省略号用到：<code>-webkit-line-clamp</code>，<code>-webkit-line-clamp</code>属性可以把块容器中的内容限制为指定的行数。它只有在<code>display</code>属性设置成<code>-webkit-box</code>或者<code>-webkit-inline-box</code>并且<code>-webkit-box-orient</code>属性设置成<code>vertical</code>时才有效果。再配合上<code>overflow: hidden</code>和<code>text-overflow: ellipsis</code>就可以实现多行文本截断展示省略号的效果了。</p><p><a href="https://code.juejin.cn/pen/7187217068771508257" target="_blank" rel="noreferrer">多行显示省略号 - 码上掘金 (juejin.cn)</a></p><h3 id="_8-实现镜像、倒影等效果-webkit-box-reflect" tabindex="-1">8. 实现镜像、倒影等效果（-webkit-box-reflect） <a class="header-anchor" href="#_8-实现镜像、倒影等效果-webkit-box-reflect" aria-label="Permalink to &quot;8. 实现镜像、倒影等效果（-webkit-box-reflect）&quot;">​</a></h3><p><code>-webkit-box-reflect</code>这个属性可以在不同方向反射元素的内容。有了这个属性，我们就可以实现一些神奇的效果，比如镜像、倒影等。</p><p><a href="https://code.juejin.cn/pen/7187217522876219448" target="_blank" rel="noreferrer">图片镜像及倒影 - 码上掘金 (juejin.cn)</a></p>`,89),c=[p];function i(d,h,u,b,F,f){return s(),a("div",null,c)}const m=e(t,[["render",i]]);export{B as __pageData,m as default};
